const m="Europe/Amsterdam";function o(e){return new Intl.DateTimeFormat("sv-SE",{timeZone:m,year:"numeric",month:"2-digit",day:"2-digit"}).format(e)}function d(e=new Date){return o(e)}function s(e,n=new Date){const t=new Date(n.getTime()+e*24*60*60*1e3);return o(t)}function u(e,n="nl-NL"){const[t,a,r]=e.split("-").map(i=>parseInt(i,10));return!t||!a||!r?"":new Intl.DateTimeFormat(n,{timeZone:m,weekday:"short"}).format(new Date(Date.UTC(t,a-1,r,12,0,0)))}export{d as a,s as b,u as w};
